+        $rsm->addFieldResult('j', 'id_1', 'id');
+        $rsm->addFieldResult('j', 'value_2', 'value');
+
+        $hydrator = new ObjectHydrator($this->_em);
+
+        $uow = $this->_em->getUnitOfWork();
+
+        $uow->createEntity(
+            GH9807Main::class,
+            ['id' => 1]
+        );
+
+        $resultSet = [
